import axios from "axios"
const url = "http://localhost:8080/api/robotApi";

//חיפוש כל הרובוטים
export const getAll = async() => {
    try {
        const {data}=await axios.get(`${url}/getAllRobots`)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}

//חיפוש רובוט לפי קוד
export const getById = async(id) => {
        try {
        const {data}=await axios.get(`${url}/getRobotById/${id}`)
        return data;
    }
    catch(e) {
        console.log(e)
    }

}

//הוספת רובוט
export const addRobot = async(robot) => {
    try {
        const {data}=await axios.post(`${url}/postRobot`,robot)
        return data;
    }
    catch(e) {
        console.log(e)
    }
}
// התיקון הקטן: הוספת /image/ לנתיב
export const getImageUrl = (img) => {
    if (!img || typeof img !== 'string' || img === "undefined") {
        return "https://via.placeholder.com/150?text=No+Image";
    }

    // 1. ניקוי מירכאות מיותרות אם נכנסו בטעות מה-DB
    let cleanImg = img.replace(/['"]+/g, '').trim();

    // 2. אם זו כתובת מלאה מהאינטרנט
    if (cleanImg.startsWith('http')) {
        return cleanImg;
    }

    // 3. טיפול בשמות בעברית/רווחים (קידוד URL)
    // encodeURIComponent הופך "מזהה באגים" לפורמט שהדפדפן מבין
    const encodedImg = encodeURIComponent(cleanImg);

    return `http://localhost:8080/image/${encodedImg}`;
};
